document.addEventListener("DOMContentLoaded", function() {
    var hamburgerBtn = document.getElementById("hamburgerBtn");
    var closeBtn = document.getElementById("closeMenuBtn");
    var sideMenu = document.getElementById("mobileSideMenu");
    var overlay = document.getElementById("mobileMenuOverlay");

    // NUCLEAR OPTION: Move menu to body to avoid container clipping/stacking context issues
    if (sideMenu && overlay) {
        document.body.appendChild(overlay);
        document.body.appendChild(sideMenu);
    }

    if (!hamburgerBtn || !sideMenu || !overlay) return;

    function openMenu() {
        sideMenu.classList.add("active");
        overlay.classList.add("active");
        document.body.style.overflow = "hidden"; // Prevent background scrolling
    }

    function closeMenu() {
        sideMenu.classList.remove("active");
        overlay.classList.remove("active");
        document.body.style.overflow = "";
    }

    hamburgerBtn.addEventListener("click", function(e) {
        e.preventDefault();
        e.stopPropagation();
        openMenu();
    });

    if (closeBtn) {
        closeBtn.addEventListener("click", function(e) {
            e.preventDefault();
            closeMenu();
        });
    }

    overlay.addEventListener("click", closeMenu);

    // Close menu when clicking a link (except special CTAs if needed)
    var menuItems = sideMenu.querySelectorAll(".mobile-menu-item:not(.cta-item)");
    menuItems.forEach(function(item) {
        item.addEventListener("click", function() {
            setTimeout(closeMenu, 200);
        });
    });

    // Handle Escape key
    document.addEventListener("keydown", function(e) {
        if (e.key === "Escape" && sideMenu.classList.contains("active")) {
            closeMenu();
        }
    });
});